package main

import (
	"html/template"
	"net/http"
)

type Comment struct {
	Author  string
	Content string
}

var comments = []Comment{
	{Author: "Alice", Content: "This is a <b>bold</b> comment."},
	{Author: "Bob", Content: "This is an <i>italic</i> comment."},
}

func commentsHandler(w http.ResponseWriter, r *http.Request) {
	tmpl := `<html>
<head><title>User Comments</title></head>
<body>
<h1>Comments</h1>
<ul>
{{range .}}
<li><strong>{{.Author}}:</strong> {{.Content}}</li>
{{end}}
</ul>
</body>
</html>`
	t, err := template.New("comments").Parse(tmpl)
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}
	err = t.Execute(w, comments)
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
	}
}

func main() {
	http.HandleFunc("/comments", commentsHandler)
	http.ListenAndServe(":8080", nil)
}